INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-814ced5a-moex-00528', 'elementary-814ced5a', 'elementary-814ced5a-moex-111-01c5eaab', 'sub-elementary-814ced5a-05', NULL, 'single_choice', '「柏克萊使我睜開眼睛，更迫切地觀察社會體認社會；在觀察和體認之餘，我並沒有感覺知識無能， 我反而更信仰知識的力量。知識是力量，但知識不可以禁閉在學院裡，知識必須釋放，放到現實社 會裡，方才是力量。學院要提供博大開放的文理科教育，所謂liberal arts 的教育，這種教育雖然可 能賦予學生日後謀生的技能，但那並不是最重要的目的；這種教育要使學生在潛默中體會到知識份 子的責任，介入社會而不為社會所埋葬──而我相信這是絕對可能的。我樂觀，因為樂觀乃是柏克萊 精神的真諦。」 根據上文，下列選項敘述正確的是：', '["柏克萊精神，是充滿樂觀與現實關懷", "知識是力量，但必須釋放到現實社會", "文理科教育主要目的是訓練謀生技能", "知識份子的責任是介入社會並保持獨立自主的判斷 學院教育與社會關懷雖有衝突，但仍必須積極調合"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:53+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "505", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00529', 'elementary-814ced5a', 'elementary-814ced5a-moex-111-01c5eaab', 'sub-elementary-814ced5a-05', NULL, 'single_choice', '「時間是善良的，還是邪惡的魔術師呢？不是，時間只是一種簡單的乘法，另把原來的數值倍增而 已。開始變壞的米飯，每一天都不斷變得更腐臭。而開始變醇的美酒，每一分鐘，都在繼續增加它 的芬芳。在人世間，我們也曾經看過天真的少年一旦開始墮落，便不免愈陷愈深，終於變得滿臉風 塵，面目可憎。但是相反的，時間卻把溫和的笑痕，體諒的眼神，成熟的風采，智慧的神韻添加在 那些追尋善良的人身上。同樣是煮熟的米，壞飯與美酒的差別在哪裡呢？就在那一點點酒麴。同樣 是父母所生，誰墮落如禽獸，而誰又能提升成完美的人呢？是內心深處，緊緊環抱不放的，求真求 善的渴望。」 依據上文，符合文意的是：', '["時間非善非惡，只會增加原本數值", "掌握利用時間，是處世智慧的關鍵", "自我如何期許，時間也會如何對待", "透過時間積累，自能達到偉大成就 時間力量強大，人類永遠無法對抗"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:53+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "505", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00530', 'elementary-814ced5a', 'elementary-814ced5a-moex-111-01c5eaab', 'sub-elementary-814ced5a-05', NULL, 'single_choice', '「幾年來，每見媒體報導校長或企業負責人在畢業典禮或尾牙時節，扮裝成天鵝、超人娛樂學生、 同仁，我總覺得痛苦不堪。痛苦的原因，並不是我反對扮裝娛人，而是我無法忍受不美的扮裝！試 想，身材已屆中年的校長與企業負責人，扮起天鵝、超人，不得不露出鬆弛的肌肉加上突出的腹部， 如何能登大雅？」 根據上文，作者認為：', '["自娛娛人難登大雅之堂", "扮裝需要兼具美感與創意", "身材不好的校長與企業負責人不當的扮裝，令人無法忍受", "畢業典禮或尾牙時，校長與企業負責人不一定要扮裝娛人 選擇天鵝與超人作為扮裝，有損校長與企業負責人的形象"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:53+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "505", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00531', 'elementary-814ced5a', 'elementary-814ced5a-moex-111-01c5eaab', 'sub-elementary-814ced5a-05', NULL, 'single_choice', '「我一直都在尋求挫敗，尋求被征服被震懾被併吞的喜悅。有人出發去『征山』，我從來不是，而 是剛好相反，我爬山，是為了被山征服。有人飛舟，是為了『凌駕』水，而我不是，如果我去親炙 水，我需要的是涓水歸川的感覺，是自身的消失，是形體的渙釋，精神的冰泮，是自我復歸位於零 的一次冒險。」 下列選項，何者符合作者所尋求的「挫敗」？', '["錯失穩操勝券的機會", "仰望浩瀚無垠的星空", "追求真摯醇美的愛情", "懾於曠世罕匹的名作 享受珍饈美饌的誘惑"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:53+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "505", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00532', 'elementary-814ced5a', 'elementary-814ced5a-moex-111-01c5eaab', 'sub-elementary-814ced5a-05', NULL, 'single_choice', '「我常向植物學習，覺得他們是最能接受命運，也最不向命運屈服的。他們不會動，種子落在哪兒， 就注定一輩子，在那裡生根、成長、死亡。如果是人，遇到這樣不平的遭遇，一定會反抗。但植物 無語，他們以另一種方式發言。在熱帶莽林中，上面是遮天的濃蔭，白天黑得像夜晚一樣，許多小 樹只能長到一呎多，就再也無法發育。他們卑微地活著，直到有一天，上面的大樹因為雷雨折斷， 他們就立刻竄上去，成為大樹。在沙漠裡，白天熱得可以烤蛋，許多種子伏在炙人的砂土下，乾得 像是砂的一部分，但是只要有一陣雨，他們就快速萌發、成長、開花。」 下列敘述，符合上文旨意的選項是：', '["人會反抗，植物不會反抗", "只要努力，不可妥協，才能成功", "植物的生長，展現出「掌握時機」的智慧", "植物雖然看似脆弱，卻具有強韌的生命力 「聽天由命」和「隨波逐流」不足以說明植物長成的道理"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:53+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "505", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00533', 'elementary-814ced5a', 'elementary-814ced5a-moex-111-01c5eaab', 'sub-elementary-814ced5a-05', NULL, 'single_choice', '「百年前，祖輩渡海來臺。彼時地景枯黃無綠，他們不分冬夏，將幾千幾百斤的汗水灑進地裡，但 乾渴的砂土仍張著龜裂大口張狂索求。被日光曬得刺燙燙的砂地如一塊烙鐵，驅趕著踩踏其上的農 人。但有人始終不走，他們直立旱地等待。日日夜夜，季季年年，終於等到灣寶庄農地重劃，興圳 建渠。可惜砂地如漏，水還未浸透，即迅速流逝。幸賴神明指引，庄民徒手徒腳、齊心齊力，共同 鏟挖庄內的紅色黏土丘，將其厚鋪於砂壤，仔細翻攪，此後，再灑下的幾千幾百斤汗水，才開始值 得。一直以來，灣寶的農民習於不著鞋履走入田地。早期因為窮困，如今則因田壟有水。泥糊糊， 溫潤潤，一踏進，就像裹上一層新生的肌膚。農人的掌有老繭，腰背僵硬，往往帶病在身。但他們 仍堅持走進農田，將鋤頭一次一次地劈進地裡。」 依據上文，下列敘述正確的是：', '["早期灣寶的地質惡劣，不利耕作", "灣寶農民以前習慣不穿鞋是因為生活貧困", "因為居住條件不佳，灣寶早已人去樓空，成為廢墟", "灣寶農民劈進地裡的不只是鋤頭，還有一股有志竟成的精神 灣寶土地改良的方式是將砂土與黏土和在一起，如此可避免砂壤大量流失"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:53+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "505", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00534', 'elementary-814ced5a', 'elementary-814ced5a-moex-111-01c5eaab', 'sub-elementary-814ced5a-05', NULL, 'single_choice', '「面對電腦的運算能力每兩年就會倍增的飆速發展，我們的社會結構一直處於落後科技發展的狀 態，唯一的方法就是增加社會的適應力，也就是要使學習的效益達到最佳化，並將創新特質運用到 文化與社會結構上，破除因循僵化、講求靈活應變，以縮短從錯誤學習的時間。大學課程的推陳出 新也日益加快，有些課程甚至已標上時效。而隨著創新週期愈來愈短，學習適應的時間愈來愈少， 我們所面對的穩定狀態也有了變化，只有不穩定的固定狀態以及偶爾不穩定狀態的差異，新的穩定 狀態必定是動態穩定，就像騎腳踏車一樣，必須在雙腳不停地踩動下一直前進。」 根據上文，說明正確的選項是：', '["人類社會的結構總是無法跟上電腦運算能力的迅速發展", "提高學習效益可增加社會的整體適應力，維持靜態穩定", "行政機關以穩定為要，避免因創新融入而帶來擾動不安", "為了符應社會變動的需求，大學開設時效課程將成為一種趨勢 最佳適應力表現在失敗後能快速修正，並維持動態平衡的前進"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:53+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "505", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00535', 'elementary-814ced5a', 'elementary-814ced5a-moex-111-01c5eaab', 'sub-elementary-814ced5a-05', NULL, 'single_choice', '下列選項，適合平行機關間使用的是：', '["「檢陳」、「附送」", "「希查照」、「附送」", "「請查照」、「附送」", "「請查照」、「希查照」 「請查照」、「敬表同意」"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:53+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "505", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00536', 'elementary-814ced5a', 'elementary-814ced5a-moex-111-c2172ccd', 'sub-elementary-814ced5a-04', NULL, 'single_choice', '下列何者是由 iSchools 成員共同建立的網路學習平台，旨在利用先進技術，透過課程共用和合作教學， 來豐富和完善圖書資訊學教育，改進學生、教師和院校之間的關係，以全面提升圖書資訊學教育品質？', '["OCWC（OpenCourseWareConsortium）", "OER（OpenEducationalResources）", "WDL（WorldDigitalLibrary）", "WISE（Web-basedInformationScienceEducation）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:54+00:00", "source_pdf_sha1": "820552f7c314", "answer_pdf_sha1": "408010958542", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "505", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "圖書館學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00537', 'elementary-814ced5a', 'elementary-814ced5a-moex-111-c2172ccd', 'sub-elementary-814ced5a-04', NULL, 'single_choice', '就中國目錄學的角度而言，目錄的主要功能不包括下列何者？', '["考證學術源流", "檢索圖書文獻", "讀書治學指引", "學術研究評論"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:54+00:00", "source_pdf_sha1": "820552f7c314", "answer_pdf_sha1": "408010958542", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "505", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "圖書館學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL)
